// Filter forwarders by specialization
const requestData = $('PostgreSQL - Read Request').first().json;
const cargoType = requestData.cargo_type;
const forwarders = $input.all();

const relevantForwarders = forwarders.filter(f => {
  const specs = (f.json.specializations || '').toLowerCase();
  const cargoMatch = specs.includes(cargoType.toLowerCase()) || 
                     specs.includes('all') || 
                     specs === '';
  return cargoMatch;
});

return relevantForwarders;

// Build email for current forwarder
const requestData = $('PostgreSQL - Read Request').first().json;
const userData = $('PostgreSQL - Read User').first().json;
const forwarderData = $json;

const emailSubject = `🚢 [NEW REQUEST] ${requestData.request_id} - ${requestData.origin} to ${requestData.destination}`;

const emailBody = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; background: #f4f4f4; }
    .container { max-width: 600px; margin: 20px auto; background: white; border-radius: 8px; overflow: hidden; box-shadow: 0 4px 6px rgba(0,0,0,0.1); }
    .header { background: #2E75B6; color: white; padding: 30px; text-align: center; }
    .header h1 { margin: 0; font-size: 28px; }
    .content { padding: 30px; }
    .request-id { font-size: 24px; font-weight: bold; color: #2E75B6; margin: 20px 0; text-align: center; border: 2px solid #2E75B6; padding: 15px; border-radius: 5px; background: #E8F4F8; }
    .details { background: #f9f9f9; padding: 20px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #2E75B6; }
    .detail-row { margin: 12px 0; display: flex; }
    .label { font-weight: bold; color: #666; min-width: 150px; }
    .value { color: #333; }
    .highlight-box { background: #FFF3CD; border: 2px solid #FFC107; padding: 15px; border-radius: 5px; margin: 20px 0; }
    .instructions { background: #E8F4F8; padding: 20px; border-radius: 5px; margin: 20px 0; }
    .footer { background: #f0f0f0; padding: 20px; text-align: center; font-size: 12px; color: #666; }
    ul { padding-left: 25px; }
    ul li { margin: 8px 0; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>🚢 New Freight Request</h1>
      <p style="margin: 10px 0 0 0; font-size: 16px;">CargoLink Marketplace</p>
    </div>
    <div class="content">
      <div class="request-id">${requestData.request_id}</div>
      <p>Dear ${forwarderData.company_name},</p>
      <p>A new freight request has been posted on CargoLink that matches your expertise.</p>
      <div class="details">
        <div class="detail-row"><span class="label">📍 Origin:</span><span class="value">${requestData.origin}</span></div>
        <div class="detail-row"><span class="label">📍 Destination:</span><span class="value">${requestData.destination}</span></div>
        <div class="detail-row"><span class="label">📦 Cargo Type:</span><span class="value">${requestData.cargo_type}</span></div>
        <div class="detail-row"><span class="label">🏷️ Commodity:</span><span class="value">${requestData.commodity || 'General Merchandise'}</span></div>
        <div class="detail-row"><span class="label">⚖️ Weight:</span><span class="value">${requestData.weight_kg} kg</span></div>
        <div class="detail-row"><span class="label">📋 Incoterms:</span><span class="value">${requestData.incoterms}</span></div>
      </div>
      <div class="highlight-box">
        <strong>⏰ IMPORTANT: First 3 Quotes Win!</strong><br>
        This request closes after <strong>3 quotations</strong>. Submit quickly!
      </div>
      <div class="instructions">
        <h3 style="margin-top: 0; color: #2E75B6;">📧 How to Submit Your Quote:</h3>
        <p><strong>Simply REPLY to this email</strong> with:</p>
        <ul>
          <li><strong>Total price</strong> (e.g., USD 2,500)</li>
          <li><strong>Transit time</strong> (in days)</li>
          <li><strong>Validity period</strong> (e.g., 7 days)</li>
          <li><strong>Carrier/shipping line</strong></li>
        </ul>
        <p><strong>⚠️ Keep the Request ID (${requestData.request_id}) in your reply subject.</strong></p>
      </div>
    </div>
    <div class="footer">
      <p><strong>CargoLink Platform</strong> — Automated notification.</p>
    </div>
  </div>
</body>
</html>`;

return {
  json: {
    email_to: forwarderData.email,
    email_subject: emailSubject,
    email_body: emailBody,
    forwarder_id: forwarderData.forwarder_id,
    forwarder_company: forwarderData.company_name,
    request_id: requestData.request_id,
    email_sent: true,
    whatsapp_sent: false,
    sent_at: new Date().toISOString()
  }
};

return {
  json: {
    forwarder_id: $json.forwarder_id,
    request_id: $json.request_id,
    status: 'PENDING',
    attempted_at: new Date().toISOString()
  }
};

// Count total forwarders notified
const gmailItems = $('Gmail - Send to Forwarder').all();
const requestData = $('PostgreSQL - Read Request').first().json;
const userData = $('PostgreSQL - Read User').first().json;

return {
  json: {
    total_notified: gmailItems.length,
    request_id: requestData.request_id,
    user_email: userData.email,
    user_name: userData.full_name
  }
};
